import { useState, useEffect, useRef } from "react";
import ReactDOM from "react-dom/client";

const LOGO_SRC = "data:image/jpeg;base64,";

const C = {
  navy: "#0D1B2A", navyLight: "#1A2E45", accent: "#E8453C",
  white: "#FFFFFF", gray: "#F4F6F9", grayMid: "#9AA5B4", text: "#1A2E45", border: "#DDE3EC",
};

const STORAGE_KEY = "gcpeasa-historial-v1";

const blankForm = () => ({
  cliente: "", fecha: new Date().toLocaleDateString("es-MX", { day: "numeric", month: "long", year: "numeric" }),
  elaboradoPor: "GCPeasa", tipoVisita: "", contacto: "", lugar: "",
  objetivo: "", temasTratados: "",
  pendientes: [{ accion: "", responsable: "", observaciones: "" }], notas: "",
  disciplinas: [],
});

/* ── helpers ── */
async function storageGet(key) {
  try { const r = await window.storage.get(key); return r?.value ?? null; } catch { return null; }
}
async function storageSet(key, value) {
  try { await window.storage.set(key, value); return true; } catch (e) { console.error("storage.set failed", e); return false; }
}

/* ── ReporteView sub-component ── */
function ReporteView({ r, onBack, backLabel }) {
  const downloadPDF = () => {
    const dg = r?.datosGenerales || {};

    // Build sections as plain strings to avoid template literal nesting issues
    const temas = (r.temasTratados || []).map((t, i) => {
      const puntos = (t.puntos||[]).map(p => '<div class="tema-punto">' + p + '</div>').join('');
      return '<div class="tema-block"><div class="tema-title">3.' + (i+1) + ' ' + t.titulo + '</div>' + puntos + '</div>';
    }).join('');

    const pendientes = (r.pendientes || []).map((p, i) =>
      '<tr><td><span class="pnum">' + (i+1) + '</span></td><td>' + (p.accion||'') + '</td><td>' + (p.responsable||'') + '</td><td>' + (p.observaciones||'') + '</td></tr>'
    ).join('');

    const notas = (r.notas || []).map(n =>
      '<div class="nota-item"><div class="nota-dot"></div><div>' + n + '</div></div>'
    ).join('');

    const disciplinas = (dg.disciplinas||[]).length
      ? '<div style="margin-top:12px"><div class="dlabel-sm">Disciplinas involucradas</div>' +
        (dg.disciplinas||[]).map(d => '<span class="disc-tag">' + d + '</span>').join('') + '</div>'
      : '';

    const notasSection = notas
      ? '<div class="sec"><div class="sec-title">5. Notas y Observaciones</div><div class="notas-box">' + notas + '</div></div>'
      : '';

    // Build logo img tag separately to avoid template literal truncation of large base64
    const logoImg = '<img src="' + LOGO_SRC + '" alt="GCPeasa" style="height:52px;object-fit:contain;display:block;" />';

    const html = '<!DOCTYPE html><html><head>' +
      '<meta charset="UTF-8"><link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Source+Sans+3:wght@400;500;600;700&display=swap">' +
      '<title>Reporte_' + (dg.cliente||'visita') + '</title>' +
      '<style>' +
      /* fonts loaded via link tag */ '' +
      '* { box-sizing: border-box; margin: 0; padding: 0; font-family: Source Sans 3, Arial, sans-serif; }' +
      'body { background: #fff; color: #1A2E45; }' +
      '.page { max-width: 800px; margin: 0 auto; }' +
      '.header { background: #0D1B2A; padding: 28px 36px; display: flex; justify-content: space-between; align-items: flex-end; }' +
      '.header-sub { font-size: 11px; letter-spacing: 3px; text-transform: uppercase; color: #9AA5B4; margin-top: 4px; }' +
      '.tag { background: #E8453C; color: #fff; font-size: 11px; padding: 5px 13px; border-radius: 3px; letter-spacing: 1px; text-transform: uppercase; font-weight: 700; }' +
      '.body { padding: 0 36px 36px; }' +
      '.sec { margin-top: 28px; }' +
      '.sec-title { font-size: 10px; letter-spacing: 2.5px; text-transform: uppercase; font-weight: 700; color: #E8453C; margin-bottom: 12px; padding-bottom: 7px; border-bottom: 2px solid #E8453C; }' +
      '.dgrid { display: grid; grid-template-columns: 1fr 1fr; border: 1px solid #DDE3EC; border-radius: 6px; overflow: hidden; }' +
      '.ditem { padding: 11px 15px; border-bottom: 1px solid #DDE3EC; }' +
      '.ditem:nth-last-child(-n+2) { border-bottom: none; }' +
      '.dlabel { font-size: 10px; letter-spacing: 1.2px; text-transform: uppercase; color: #9AA5B4; font-weight: 600; margin-bottom: 2px; }' +
      '.dval { font-size: 14px; font-weight: 500; }' +
      '.objbox { background: #F4F6F9; border-left: 3px solid #0D1B2A; padding: 14px 18px; border-radius: 0 6px 6px 0; font-size: 14px; line-height: 1.7; }' +
      '.tema-block { margin-bottom: 18px; }' +
      '.tema-title { font-size: 13px; font-weight: 700; color: #0D1B2A; margin-bottom: 7px; }' +
      '.tema-punto { font-size: 13px; padding: 4px 0 4px 16px; position: relative; line-height: 1.5; }' +
      '.tema-punto::before { content: "\u2022"; position: absolute; left: 3px; color: #E8453C; font-weight: 700; }' +
      'table { width: 100%; border-collapse: collapse; font-size: 13px; }' +
      'thead tr { background: #0D1B2A; color: #fff; }' +
      'th { padding: 9px 13px; text-align: left; font-size: 10px; letter-spacing: 1.2px; text-transform: uppercase; font-weight: 600; }' +
      'td { padding: 9px 13px; border-bottom: 1px solid #DDE3EC; vertical-align: top; }' +
      'tr:nth-child(even) td { background: #F4F6F9; }' +
      '.pnum { display: inline-flex; width: 20px; height: 20px; background: #0D1B2A; color: #fff; border-radius: 50%; align-items: center; justify-content: center; font-size: 10px; font-weight: 700; }' +
      '.nota-item { display: flex; gap: 10px; padding: 8px 0; border-bottom: 1px solid #DDE3EC; }' +
      '.nota-item:last-child { border-bottom: none; }' +
      '.nota-dot { width: 6px; height: 6px; border-radius: 50%; background: #E8453C; flex-shrink: 0; margin-top: 6px; }' +
      '.notas-box { background: #F4F6F9; border-radius: 6px; padding: 8px 16px; }' +
      '.footer { margin-top: 40px; padding-top: 20px; border-top: 1px solid #DDE3EC; display: flex; justify-content: space-between; font-size: 11px; color: #9AA5B4; }' +
      '.disc-tag { display:inline-block; background: #0D1B2A; color: #fff; font-size: 11px; font-weight: 700; padding: 3px 10px; border-radius: 20px; margin: 3px 4px 3px 0; }' +
      '.dlabel-sm { font-size: 10px; letter-spacing: 1.2px; text-transform: uppercase; color: #9AA5B4; font-weight: 600; margin-bottom: 6px; }' +
      '@media print { @page { margin: 0; size: A4; } body { margin: 1.5cm; } }' +
      '</style></head><body>' +
      '<div class="page">' +
        '<div class="header">' +
          '<div>' + logoImg + '<div class="header-sub">Reporte de Visita a Cliente</div></div>' +
          '<div class="tag">Confidencial</div>' +
        '</div>' +
        '<div class="body">' +
          '<div class="sec"><div class="sec-title">1. Datos Generales</div>' +
            '<div class="dgrid">' +
              '<div class="ditem"><div class="dlabel">Cliente</div><div class="dval">' + (dg.cliente||'—') + '</div></div>' +
              '<div class="ditem"><div class="dlabel">Fecha</div><div class="dval">' + (dg.fecha||'—') + '</div></div>' +
              '<div class="ditem"><div class="dlabel">Elaborado por</div><div class="dval">' + (dg.elaboradoPor||'—') + '</div></div>' +
              '<div class="ditem"><div class="dlabel">Tipo de visita</div><div class="dval">' + (dg.tipoVisita||'—') + '</div></div>' +
              '<div class="ditem"><div class="dlabel">Contacto cliente</div><div class="dval">' + (dg.contacto||'—') + '</div></div>' +
              '<div class="ditem"><div class="dlabel">Lugar</div><div class="dval">' + (dg.lugar||'—') + '</div></div>' +
            '</div>' +
          '</div>' +
          disciplinas +
          '<div class="sec"><div class="sec-title">2. Objetivo de la Visita</div><div class="objbox">' + (r.objetivo||'') + '</div></div>' +
          '<div class="sec"><div class="sec-title">3. Temas Tratados</div>' + temas + '</div>' +
          '<div class="sec"><div class="sec-title">4. Pendientes y Siguientes Pasos</div>' +
            '<table><thead><tr><th>#</th><th>Acción / Pendiente</th><th>Responsable</th><th>Observaciones</th></tr></thead>' +
            '<tbody>' + pendientes + '</tbody></table>' +
          '</div>' +
          notasSection +
          '<div class="footer"><span>GCPeasa | Aguascalientes, México</span><span>Confidencial — Uso interno</span></div>' +
        '</div>' +
      '</div>' +
      '<div style="text-align:center;padding:20px;background:#f4f6f9;border-top:1px solid #dde3ec">' +
        '<button onclick="window.print()" style="background:#E8453C;color:#fff;border:none;padding:12px 32px;border-radius:6px;font-size:15px;font-weight:700;cursor:pointer;font-family:Arial,sans-serif">🖨 Imprimir / Guardar como PDF</button>' +
        '<p style="font-size:12px;color:#9AA5B4;margin-top:10px;font-family:Arial,sans-serif">En el diálogo, selecciona <b>Guardar como PDF</b> como destino</p>' +
      '</div>' +
      '</body></html>';


    const blob = new Blob([html], { type: "text/html;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    const cliente = (dg.cliente || "reporte").replace(/[^a-zA-Z0-9]/g, "_");
    const fecha = (dg.fecha || "fecha").replace(/[^a-zA-Z0-9]/g, "_");
    a.href = url;
    a.download = `Reporte_${cliente}_${fecha}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
  };

  return (
    <>
      <div className="bar no-print" style={{ justifyContent: "space-between" }}>
        <button className="btn ghost" onClick={onBack}>← {backLabel}</button>
        <div style={{ display: "flex", gap: 8 }}>
          <button className="btn dark" onClick={() => window.print()}>🖨 Imprimir</button>
          <button className="btn primary" onClick={downloadPDF}>
            ⬇ Descargar Reporte
          </button>
        </div>
      </div>
      <div className="rpage">
        <div className="rheader">
          <div>
            <img src={LOGO_SRC} alt="GCPeasa" style={{ height: 50, objectFit: "contain", filter: "none" }} />
            <div style={{ fontFamily: "sans-serif", fontSize: 11, letterSpacing: 3, textTransform: "uppercase", color: C.grayMid, marginTop: 4 }}>Reporte de Visita a Cliente</div>
          </div>
          <div className="rtag">Confidencial</div>
        </div>
        <div className="rbody">
          {/* 1 */}
          <div className="rsec"><div className="rstitle">1. Datos Generales</div>
            <div className="dgrid">
              {[["Cliente", r.datosGenerales?.cliente], ["Fecha", r.datosGenerales?.fecha],
                ["Elaborado por", r.datosGenerales?.elaboradoPor], ["Tipo de visita", r.datosGenerales?.tipoVisita],
                ["Contacto cliente", r.datosGenerales?.contacto], ["Lugar", r.datosGenerales?.lugar],
              ].map(([l, v]) => (
                <div key={l} className="ditem"><div className="dlabel">{l}</div><div className="dval">{v || "—"}</div></div>
              ))}
            </div>
            {r.datosGenerales?.disciplinas?.length > 0 && (
              <div style={{ marginTop: 12 }}>
                <div className="dlabel" style={{ marginBottom: 8 }}>Disciplinas involucradas</div>
                <div className="disc-tags">
                  {r.datosGenerales.disciplinas.map(d => <span key={d} className="disc-tag">{d}</span>)}
                </div>
              </div>
            )}
          </div>
          {/* 2 */}
          <div className="rsec"><div className="rstitle">2. Objetivo de la Visita</div>
            <div className="objbox">{r.objetivo}</div>
          </div>
          {/* 3 */}
          <div className="rsec"><div className="rstitle">3. Temas Tratados</div>
            {(r.temasTratados || []).map((t, i) => (
              <div key={i} style={{ marginBottom: 18 }}>
                <div className="tematitle">3.{i + 1} {t.titulo}</div>
                {(t.puntos || []).map((p, j) => <div key={j} className="temapunto">{p}</div>)}
              </div>
            ))}
          </div>
          {/* 4 */}
          <div className="rsec"><div className="rstitle">4. Pendientes y Siguientes Pasos</div>
            <table className="ptable">
              <thead><tr><th>#</th><th>Acción / Pendiente</th><th>Responsable</th><th>Observaciones</th></tr></thead>
              <tbody>
                {(r.pendientes || []).map((p, i) => (
                  <tr key={i}>
                    <td><span className="pnum">{i + 1}</span></td>
                    <td>{p.accion}</td><td>{p.responsable}</td><td>{p.observaciones}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {/* 5 */}
          {r.notas?.length > 0 && (
            <div className="rsec"><div className="rstitle">5. Notas y Observaciones</div>
              <div style={{ background: C.gray, borderRadius: 6, padding: "8px 16px" }}>
                {r.notas.map((n, i) => (
                  <div key={i} style={{ display: "flex", gap: 10, padding: "8px 0", borderBottom: i < r.notas.length - 1 ? `1px solid ${C.border}` : "none" }}>
                    <div style={{ width: 6, height: 6, borderRadius: "50%", background: C.accent, flexShrink: 0, marginTop: 6 }} />
                    <div style={{ fontFamily: "sans-serif", fontSize: 13, color: C.text, lineHeight: 1.6 }}>{n}</div>
                  </div>
                ))}
              </div>
            </div>
          )}
          <div style={{ marginTop: 40, paddingTop: 20, borderTop: `1px solid ${C.border}`, display: "flex", justifyContent: "space-between", fontFamily: "sans-serif", fontSize: 11, color: C.grayMid }}>
            <span>GCPeasa | Aguascalientes, México</span>
            <span>Confidencial — Uso interno</span>
          </div>
        </div>
      </div>
    </>
  );
}

/* ── Main ── */
export default function App() {
  const [form, setForm] = useState(blankForm());
  const [step, setStep] = useState("form"); // form | report | historial | view
  const [loading, setLoading] = useState(false);
  const [reporte, setReporte] = useState(null);
  const [historial, setHistorial] = useState([]);
  const [histLoaded, setHistLoaded] = useState(false);
  const [selected, setSelected] = useState(null);
  const [toast, setToast] = useState(null);
  const histRef = useRef([]);

  const toast2 = (msg, err = false) => { setToast({ msg, err }); setTimeout(() => setToast(null), 4000); };

  // sync ref with state
  useEffect(() => { histRef.current = historial; }, [historial]);

  // load on mount
  useEffect(() => {
    (async () => {
      const raw = await storageGet(STORAGE_KEY);
      if (raw) {
        try {
          const arr = JSON.parse(raw);
          if (Array.isArray(arr)) { setHistorial(arr); histRef.current = arr; }
        } catch {}
      }
      setHistLoaded(true);
    })();
  }, []);

  const persist = async (arr) => {
    const ok = await storageSet(STORAGE_KEY, JSON.stringify(arr));
    if (ok) toast2("✓ Guardado en historial");
    else toast2("⚠ No se pudo guardar en historial", true);
  };

  const addToHistorial = (rep) => {
    const entry = { id: String(Date.now()), savedAt: new Date().toISOString(), reporte: rep };
    const updated = [entry, ...histRef.current];
    setHistorial(updated);
    histRef.current = updated;
    persist(updated); // fire and forget — never blocks UI
  };

  const deleteEntry = async (id) => {
    const updated = histRef.current.filter((h) => h.id !== id);
    setHistorial(updated);
    histRef.current = updated;
    await storageSet(STORAGE_KEY, JSON.stringify(updated));
    toast2("Reporte eliminado");
  };

  const upd = (k, v) => setForm((f) => ({ ...f, [k]: v }));
  const addPend = () => setForm((f) => ({ ...f, pendientes: [...f.pendientes, { accion: "", responsable: "", observaciones: "" }] }));
  const updPend = (i, k, v) => setForm((f) => { const p = [...f.pendientes]; p[i] = { ...p[i], [k]: v }; return { ...f, pendientes: p }; });
  const delPend = (i) => setForm((f) => ({ ...f, pendientes: f.pendientes.filter((_, j) => j !== i) }));

  const generar = async () => {
    if (!form.cliente.trim()) { toast2("Ingresa el nombre del cliente", true); return; }
    setLoading(true);
    setReporte(null);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1500,
          messages: [{
            role: "user",
            content: `Eres asistente de GCPeasa. Genera un reporte de visita a cliente en español.
Devuelve ÚNICAMENTE un objeto JSON válido sin backticks ni texto extra, con esta estructura:
{"datosGenerales":{"cliente":"...","fecha":"...","elaboradoPor":"...","tipoVisita":"...","contacto":"...","lugar":"...","disciplinas":["..."]},"objetivo":"...","temasTratados":[{"titulo":"...","puntos":["..."]}],"pendientes":[{"accion":"...","responsable":"...","observaciones":"..."}],"notas":["..."]}

Datos:
- Cliente: ${form.cliente}
- Fecha: ${form.fecha}
- Elaborado por: ${form.elaboradoPor}
- Tipo de visita: ${form.tipoVisita}
- Contacto: ${form.contacto}
- Lugar: ${form.lugar}
- Objetivo: ${form.objetivo}
- Temas tratados: ${form.temasTratados}
- Pendientes: ${JSON.stringify(form.pendientes)}
- Disciplinas involucradas: ${form.disciplinas.length ? form.disciplinas.join(', ') : 'No especificadas'}
- Notas: ${form.notas}`,
          }],
        }),
      });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const raw = (data.content || []).map((b) => b.text || "").join("").replace(/```json|```/g, "").trim();
      const parsed = JSON.parse(raw);
      setReporte(parsed);
      setStep("report");
      addToHistorial(parsed);
    } catch (e) {
      console.error("generar error:", e);
      toast2(`Error: ${e.message || "intenta de nuevo"}`, true);
    }
    setLoading(false);
  };

  const resetForm = () => { setForm(blankForm()); setReporte(null); setStep("form"); };

  return (
    <div style={{ minHeight: "100vh", background: C.gray }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Source+Sans+3:wght@400;500;600;700&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body, div, span, input, textarea, button, th, td { font-family: 'Source Sans 3', sans-serif; }
        .hdr { background: ${C.navy}; padding: 18px 32px; display: flex; align-items: center; justify-content: space-between; }
        .hnav { display: flex; gap: 8px; }
        .nbtn { padding: 8px 16px; border-radius: 6px; border: 1px solid rgba(255,255,255,0.2); background: transparent; color: rgba(255,255,255,0.65); font-size: 13px; font-weight: 600; cursor: pointer; transition: all .2s; }
        .nbtn:hover { background: rgba(255,255,255,0.1); color: #fff; }
        .nbtn.on { background: ${C.accent}; color: #fff; border-color: ${C.accent}; }
        .wrap { max-width: 860px; margin: 0 auto; padding: 32px 20px; }
        .card { background: #fff; border-radius: 8px; box-shadow: 0 2px 12px rgba(0,0,0,.07); overflow: hidden; margin-bottom: 16px; }
        .ch { background: ${C.navy}; color: #fff; padding: 11px 22px; font-size: 11px; letter-spacing: 2px; text-transform: uppercase; font-weight: 700; }
        .cb { padding: 22px; }
        .g2 { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }
        .g3 { display: grid; grid-template-columns: 2fr 1.2fr 1.8fr; gap: 10px; align-items: end; }
        lbl { display: block; font-size: 11px; font-weight: 700; color: ${C.grayMid}; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 5px; margin-top: 14px; }
        lbl:first-of-type { margin-top: 0; }
        input, textarea { width: 100%; padding: 9px 13px; border: 1px solid ${C.border}; border-radius: 6px; font-size: 14px; color: ${C.text}; background: ${C.gray}; outline: none; transition: border .15s; }
        input:focus, textarea:focus { border-color: ${C.navy}; background: #fff; }
        textarea { resize: vertical; min-height: 85px; }
        .btn { padding: 10px 24px; border: none; border-radius: 6px; font-size: 14px; font-weight: 700; cursor: pointer; transition: all .2s; }
        .btn.primary { background: ${C.accent}; color: #fff; }
        .btn.primary:hover:not(:disabled) { background: #c73830; transform: translateY(-1px); }
        .btn.primary:disabled { opacity: 0.6; cursor: not-allowed; }
        .btn.dark { background: ${C.navy}; color: #fff; }
        .btn.dark:hover { background: ${C.navyLight}; }
        .btn.ghost { background: transparent; color: ${C.grayMid}; border: 1px solid ${C.border}; }
        .btn.ghost:hover { background: ${C.gray}; }
        .btn.sm { padding: 6px 12px; font-size: 12px; }
        .btn.danger { background: #fff0ef; color: ${C.accent}; border: 1px solid #ffd0ce; }
        .disc-grid { display: flex; gap: 12px; flex-wrap: wrap; margin-top: 8px; }
        .disc-chip { display: flex; align-items: center; gap: 8px; padding: 8px 16px; border: 2px solid ${C.border}; border-radius: 8px; cursor: pointer; font-size: 13px; font-weight: 600; color: ${C.grayMid}; background: ${C.gray}; transition: all .15s; user-select: none; }
        .disc-chip.active { border-color: ${C.navy}; background: ${C.navy}; color: #fff; }
        .disc-chip input { display: none; }
        .disc-tags { display: flex; gap: 6px; flex-wrap: wrap; margin-top: 10px; }
        .disc-tag { background: ${C.navy}; color: #fff; font-size: 11px; font-weight: 700; padding: 3px 10px; border-radius: 20px; letter-spacing: 0.5px; }
        .bar { display: flex; gap: 10px; justify-content: flex-end; padding: 16px 0; }
        .prow { background: ${C.gray}; border-radius: 8px; padding: 14px 14px 14px 44px; margin-bottom: 10px; position: relative; }
        .pnum-abs { position: absolute; top: 14px; left: 12px; width: 22px; height: 22px; background: ${C.navy}; color: #fff; border-radius: 50%; font-size: 11px; font-weight: 700; display: flex; align-items: center; justify-content: center; }
        /* REPORT */
        .rpage { background: #fff; border-radius: 8px; box-shadow: 0 2px 20px rgba(0,0,0,.1); overflow: hidden; }
        .rheader { background: ${C.navy}; padding: 28px 36px; display: flex; justify-content: space-between; align-items: flex-end; }
        .rtag { background: ${C.accent}; color: #fff; font-size: 11px; padding: 5px 13px; border-radius: 3px; letter-spacing: 1px; text-transform: uppercase; font-weight: 700; }
        .rbody { padding: 0 36px 36px; }
        .rsec { margin-top: 28px; }
        .rstitle { font-size: 10px; letter-spacing: 2.5px; text-transform: uppercase; font-weight: 700; color: ${C.accent}; margin-bottom: 12px; padding-bottom: 7px; border-bottom: 2px solid ${C.accent}; }
        .dgrid { display: grid; grid-template-columns: 1fr 1fr; border: 1px solid ${C.border}; border-radius: 6px; overflow: hidden; }
        .ditem { padding: 11px 15px; border-bottom: 1px solid ${C.border}; }
        .ditem:nth-last-child(-n+2) { border-bottom: none; }
        .dlabel { font-size: 10px; letter-spacing: 1.2px; text-transform: uppercase; color: ${C.grayMid}; font-weight: 600; margin-bottom: 2px; }
        .dval { font-size: 14px; color: ${C.text}; font-weight: 500; }
        .objbox { background: ${C.gray}; border-left: 3px solid ${C.navy}; padding: 14px 18px; border-radius: 0 6px 6px 0; font-size: 14px; line-height: 1.7; color: ${C.text}; }
        .tematitle { font-size: 13px; font-weight: 700; color: ${C.navy}; margin-bottom: 7px; }
        .temapunto { font-size: 13px; color: ${C.text}; padding: 4px 0 4px 16px; position: relative; line-height: 1.5; }
        .temapunto::before { content:"•"; position: absolute; left: 3px; color: ${C.accent}; font-weight: 700; }
        .ptable { width: 100%; border-collapse: collapse; font-size: 13px; }
        .ptable thead tr { background: ${C.navy}; color: #fff; }
        .ptable th { padding: 9px 13px; text-align: left; font-size: 10px; letter-spacing: 1.2px; text-transform: uppercase; font-weight: 600; }
        .ptable td { padding: 9px 13px; border-bottom: 1px solid ${C.border}; vertical-align: top; }
        .ptable tr:nth-child(even) td { background: ${C.gray}; }
        .pnum { display: inline-flex; width: 20px; height: 20px; background: ${C.navy}; color: #fff; border-radius: 50%; align-items: center; justify-content: center; font-size: 10px; font-weight: 700; }
        /* HISTORIAL */
        .hcard { background: #fff; border-radius: 8px; box-shadow: 0 2px 10px rgba(0,0,0,.06); padding: 18px 22px; margin-bottom: 10px; display: flex; align-items: center; justify-content: space-between; border-left: 4px solid ${C.navy}; transition: box-shadow .2s, transform .15s; cursor: pointer; }
        .hcard:hover { box-shadow: 0 4px 18px rgba(0,0,0,.12); transform: translateY(-1px); }
        .hcliente { font-size: 16px; font-weight: 700; color: ${C.text}; margin-bottom: 4px; }
        .hmeta { font-size: 12px; color: ${C.grayMid}; display: flex; gap: 14px; flex-wrap: wrap; }
        .hbadge { background: ${C.gray}; color: ${C.navy}; font-size: 11px; font-weight: 700; padding: 2px 9px; border-radius: 20px; }
        /* TOAST */
        .toast { position: fixed; bottom: 24px; right: 24px; padding: 12px 20px; border-radius: 8px; font-size: 14px; font-weight: 600; box-shadow: 0 4px 20px rgba(0,0,0,.2); z-index: 9999; color: #fff; animation: tup .25s ease; }
        @keyframes tup { from { opacity:0; transform: translateY(12px); } to { opacity:1; transform: translateY(0); } }
        /* SPIN */
        .spin { display: inline-block; width: 16px; height: 16px; border: 2px solid rgba(255,255,255,.35); border-top-color: #fff; border-radius: 50%; animation: sp .7s linear infinite; vertical-align: middle; margin-right: 8px; }
        @keyframes sp { to { transform: rotate(360deg); } }
        @media print { .no-print { display: none !important; } body { background: #fff; } .rpage { box-shadow: none; } }
      `}</style>

      {/* Header */}
      <div className="hdr">
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <img src={LOGO_SRC} alt="GCPeasa" style={{ height: 46, objectFit: "contain" }} />
          <div style={{ width: 1, height: 34, background: "rgba(255,255,255,.18)" }} />
          <span style={{ fontSize: 12, color: C.grayMid, letterSpacing: "1.5px", textTransform: "uppercase" }}>Reportes de Visita</span>
        </div>
        <div className="hnav no-print">
          <button className={`nbtn ${step === "form" || step === "report" ? "on" : ""}`} onClick={resetForm}>+ Nueva Visita</button>
          <button className={`nbtn ${step === "historial" || step === "view" ? "on" : ""}`} onClick={() => setStep("historial")}>
            📋 Historial {historial.length > 0 && `(${historial.length})`}
          </button>
        </div>
      </div>

      <div className="wrap">

        {/* ── FORM ── */}
        {step === "form" && (<>
          <div className="card">
            <div className="ch">1. Datos Generales</div>
            <div className="cb">
              <div className="g2">
                <div><lbl>Cliente *</lbl><input placeholder="Ej. Texas Instruments" value={form.cliente} onChange={e => upd("cliente", e.target.value)} /></div>
                <div><lbl>Fecha</lbl><input value={form.fecha} onChange={e => upd("fecha", e.target.value)} /></div>
                <div><lbl>Elaborado por</lbl><input value={form.elaboradoPor} onChange={e => upd("elaboradoPor", e.target.value)} /></div>
                <div><lbl>Tipo de visita</lbl><input placeholder="Ej. Presentación, Seguimiento..." value={form.tipoVisita} onChange={e => upd("tipoVisita", e.target.value)} /></div>
                <div><lbl>Contacto cliente</lbl><input placeholder="Nombre y cargo" value={form.contacto} onChange={e => upd("contacto", e.target.value)} /></div>
                <div><lbl>Lugar</lbl><input placeholder="Instalaciones, dirección..." value={form.lugar} onChange={e => upd("lugar", e.target.value)} /></div>
              </div>
            </div>
          </div>
          <div className="card">
            <div className="ch">2. Disciplinas Involucradas</div>
            <div className="cb">
              <lbl>Selecciona las áreas que participan en esta visita</lbl>
              <div className="disc-grid">
                {["Diseño / Arq", "Ingeniería", "Costos", "Generales (Admon, Legal)"].map(d => {
                  const active = form.disciplinas.includes(d);
                  return (
                    <label key={d} className={`disc-chip ${active ? "active" : ""}`} onClick={() =>
                      upd("disciplinas", active ? form.disciplinas.filter(x => x !== d) : [...form.disciplinas, d])
                    }>
                      <span>{active ? "✓" : "○"}</span> {d}
                    </label>
                  );
                })}
              </div>
            </div>
          </div>
          <div className="card">
            <div className="ch">3. Objetivo de la Visita</div>
            <div className="cb"><lbl>Describe el objetivo</lbl><textarea placeholder="Ej. Presentar avances, revisar especificaciones, alinear próximos pasos..." value={form.objetivo} onChange={e => upd("objetivo", e.target.value)} /></div>
          </div>
          <div className="card">
            <div className="ch">4. Temas Tratados</div>
            <div className="cb"><lbl>Describe los temas (de forma libre)</lbl><textarea style={{ minHeight: 110 }} placeholder="Ej. Se presentaron dos opciones. El cliente pidió cotización por hora hombre..." value={form.temasTratados} onChange={e => upd("temasTratados", e.target.value)} /></div>
          </div>
          <div className="card">
            <div className="ch">5. Pendientes y Siguientes Pasos</div>
            <div className="cb">
              {form.pendientes.map((p, i) => (
                <div key={i} className="prow">
                  <div className="pnum-abs">{i + 1}</div>
                  <div className="g3">
                    <div><lbl>Acción</lbl><input placeholder="Descripción" value={p.accion} onChange={e => updPend(i, "accion", e.target.value)} /></div>
                    <div><lbl>Responsable</lbl><input placeholder="Quién" value={p.responsable} onChange={e => updPend(i, "responsable", e.target.value)} /></div>
                    <div><lbl>Observaciones</lbl>
                      <div style={{ display: "flex", gap: 6 }}>
                        <input placeholder="Notas" value={p.observaciones} onChange={e => updPend(i, "observaciones", e.target.value)} />
                        {form.pendientes.length > 1 && <button className="btn sm danger" onClick={() => delPend(i)}>✕</button>}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
              <button className="btn ghost sm" onClick={addPend}>+ Agregar pendiente</button>
            </div>
          </div>
          <div className="card">
            <div className="ch">6. Notas y Observaciones</div>
            <div className="cb"><lbl>Notas importantes</lbl><textarea placeholder="Ej. El proyecto no puede avanzar sin levantamiento en sitio..." value={form.notas} onChange={e => upd("notas", e.target.value)} /></div>
          </div>
          <div className="bar no-print">
            <button className="btn primary" onClick={generar} disabled={loading || !form.cliente.trim()}>
              {loading ? <><span className="spin" />Generando...</> : "✦ Generar Reporte"}
            </button>
          </div>
        </>)}

        {/* ── REPORT ── */}
        {step === "report" && reporte && (
          <ReporteView r={reporte} onBack={resetForm} backLabel="Nueva visita" />
        )}

        {/* ── HISTORIAL ── */}
        {step === "historial" && (<>
          {!histLoaded ? (
            <div style={{ textAlign: "center", padding: 60, color: C.grayMid }}>Cargando historial...</div>
          ) : historial.length === 0 ? (
            <div style={{ textAlign: "center", padding: 60, color: C.grayMid }}>
              <div style={{ fontSize: 48, marginBottom: 14 }}>📋</div>
              <div style={{ fontSize: 16, marginBottom: 6 }}>No hay reportes guardados</div>
              <div style={{ fontSize: 13 }}>Genera tu primera visita con "+ Nueva Visita"</div>
            </div>
          ) : (<>
            <div style={{ fontSize: 12, color: C.grayMid, marginBottom: 14 }}>{historial.length} reporte{historial.length !== 1 ? "s" : ""} guardado{historial.length !== 1 ? "s" : ""}</div>
            {historial.map(entry => (
              <div key={entry.id} className="hcard" onClick={() => { setSelected(entry); setStep("view"); }}>
                <div style={{ flex: 1 }}>
                  <div className="hcliente">{entry.reporte?.datosGenerales?.cliente || "Sin cliente"}</div>
                  <div className="hmeta">
                    <span>📅 {entry.reporte?.datosGenerales?.fecha}</span>
                    <span>📍 {entry.reporte?.datosGenerales?.lugar || "—"}</span>
                    {entry.reporte?.datosGenerales?.tipoVisita && <span className="hbadge">{entry.reporte.datosGenerales.tipoVisita}</span>}
                  </div>
                </div>
                <div style={{ display: "flex", gap: 8, marginLeft: 14 }} onClick={e => e.stopPropagation()}>
                  <button className="btn dark sm" onClick={() => { setSelected(entry); setStep("view"); }}>Ver</button>
                  <button className="btn danger sm" onClick={() => { if (window.confirm("¿Eliminar este reporte?")) deleteEntry(entry.id); }}>🗑</button>
                </div>
              </div>
            ))}
          </>)}
        </>)}

        {/* ── VIEW SAVED ── */}
        {step === "view" && selected && (
          <ReporteView r={selected.reporte} onBack={() => setStep("historial")} backLabel="Historial" />
        )}

      </div>

      {toast && (
        <div className="toast no-print" style={{ background: toast.err ? C.accent : C.navy }}>{toast.msg}</div>
      )}
    </div>
  );
}

// Mount app
ReactDOM.createRoot(document.getElementById("root")).render(<App />);
